  ('medical-tech-moex-06072', 'medical-tech', 'medical-tech-moex-108-bccd9a5a', 'sub-medical-tech-05', NULL, 'single_choice', '臺灣中部某⼩學數名學童先後在5⽇內發⽣下痢的事件，症狀包含腹瀉、發燒、嘔吐、裏急後重 （tenesmus）。由病童的糞便中及該校洗⼿⽤的地下⽔中，分離出⼀株不會發酵乳糖、無運動性之腸內桿菌 科（Enterobacteriaceae）細菌。衛⽣單位對病童施以居家隔離，學校環境進⾏消毒後，疫情幸未再擴⼤。 下列菌屬中，何者最有可能是造成此次事件的元兇？', '["埃希⽒菌屬（Escherichia）", "沙⾨⽒菌屬（Salmonella）", "志賀⽒菌屬（Shigella）", "耶爾辛⽒菌屬（Yersinia）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:26+00:00", "source_pdf_sha1": "a8e3b07f33c8", "answer_pdf_sha1": "e3da1ba3154d", "source_family": "moex-gov-tw", "moex": {"exam_code": "108030", "c": "308", "s": "44", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學與臨床微生物學（包括細菌與黴菌）", "year": "108", "exam_name": "108年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸治療師、獸醫師考試", "original_question_number": 79, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
